") # تحلیل TreeExplainer print("اجرای TreeExplainer...") for i, target in enumerate(tqdm(targets, desc="تحلیل TreeExplainer")): try: stacking_for_target = best_model.estimators_[i] lgbm_model = stacking_for_target.named_estimators_["lgbm"] explainer = TreeExplainer(lgbm_model) shap_values = explainer.shap_values(X_test.values) plt.figure(figsize=(10, 6)) sns.barplot(x=np.abs(shap_values).mean(0), y=best_features) plt.title(f"SHAP Values for {target} (LGBM)") plt.savefig(os.path.join(output_path, f"shap_bar_{target}_lgbm.png")) plt.close() with open(os.path.join(output_path, f"shap_bar_{target}_lgbm.txt"), "w") as f: f.write(str(pd.Series(np.abs(shap_values).mean(0), index=best_features))) except Exception as e: print(f"خطا در تحلیل SHAP برای هدف {target}: {e}") continue # نمودارهای اضافی # هیستوگرام برای CanopyTempDeficit_Mean if "CanopyTempDeficit_Mean" in data.columns: plt.figure(figsize=(10, 6)) plt.hist(data["CanopyTempDeficit_Mean"], bins=20) plt.title("Histogram of CanopyTempDeficit_Mean") plt.savefig(os.path.join(output_path, "histogram_CanopyTempDeficit_Mean.png")) plt.close() with open(os.path.join(output_path, "histogram_CanopyTempDeficit_Mean.txt"), "w") as f: f.write(str(data["CanopyTempDeficit_Mean"].describe())) else: print("ستون 'CanopyTempDeficit_Mean' در داده‌ها پیدا نشد. هیستوگرام تولید نمی‌شود.") # Scatter Plot با معادله خط و معیارها for target in targets: for dataset, y_true, y_pred in [("Test", y_test[target], y_pred_test[:, targets.index(target)]), ("Validation", y_val[target], y_pred_val[:, targets.index(target)])]: plt.figure(figsize=(10, 6)) plt.scatter(y_true, y_pred, alpha=0.5) plt.plot([y_true.min(), y_true.max()], [y_true.min(), y_true.max()], "r--", label="1:1 Line") # خط رگرسیون m, b = np.polyfit(y_true, y_pred, 1) plt.plot(y_true, m*y_true + b, "b-", label=f"y={m:.2f}x+{b:.2f}") # معیارها r2 = r2_score(y_true, y_pred) rmse = np.sqrt(mean_squared_error(y_true, y_pred)) plt.legend(title=f"R²: {r2:.4f}
